  "version": "0.0.0",
  "private": true,
  "packageManager": "pnpm@10.11.0",
  "engines": {
    "node": ">=22.0.0"
  },
  "scripts": {
    "build": "pnpm -r --filter !root run build",
    "lint": "pnpm -r --filter !root run lint",
    "format": "pnpm -r --filter !root run format",
    "typecheck": "pnpm -r --filter !root run typecheck",
    "test": "pnpm -r --filter !root run test",
    "e2e": "pnpm -r --filter Web run e2e",
    "dev": "pnpm -r --filter Web run dev"
  },
  "devDependencies": {
    "@biomejs/biome": "^2.4.15",
    "typescript": "^6.0.3"
  }
}

{
	"$schema": "https://biomejs.dev/schemas/2.4.15/schema.json",
	"vcs": {
		"enabled": true,
		"clientKind": "git",
		"useIgnoreFile": true
	},
	"files": {
		"ignoreUnknown": false,
		"includes": ["**", "!/apps/console/dist/**", "!/apps/web/.next/**"]
	},
	"formatter": {
		"enabled": true,
		"indentStyle": "tab"
	},
	"organizeImports": {
		"enabled": true
	},
	"linter": {
		"enabled": true,
		"rules": {
			"recommended": true
		}
	},
	"javascript": {
		"formatter": {
			"quoteStyle": "double"
		}
	}
}

interface ChatItem {
    id: string;
    role: 'user' | 'assistant' | 'error';
    text: string;
    is_last: boolean;
}

interface HTMLContent {
    html: string;
    details: {
        thinking_time: number;
        citations: Array<{Number: number; URL: string}>;
    };
}

const lastChatId = 'chat-2';
const finalChatItem: ChatItem = { id: 'chat-2', role: 'user', text: 'Test', is_last: true };
const htmlContent: HTMLContent = {
    html: '<p>Hello world</p><ul><li>One</li><li>Two</li></ul>',
    details: {
        thinking_time: 1.23,
        citations: [{Number: 1, URL: 'https://example.com'}]
    }
};

function parseCitation(Url: string): [number, string] {
    const match = Url.match(/\[(\d+)\]/);
    const num = match ? parseInt(match[1], 10) : 0;
    return [num, Url];
}

(window as any).chatHistory = [finalChatItem];
(window as any).currentChatId = lastChatId;

{
  "name": "myapp-lib",
  "version": "0.0.0",
  "private": true,
  "type": "module",
  "exports": {
    ".": {
      "import": {
        "types": "./dist/index.d.ts",
        "default": "./dist/index.js"
      }
    }
  },
  "scripts": {
    "build": "tsc",
    "lint": "biome check --write .",
    "format": "biome format --write .",
    "typecheck": "tsc --noEmit",
    "test": "vitest run"
  },
  "devDependencies": {
    "typescript": "^6.0.3",
    "vitest": "^4.1.7"
  }
}

{
  "extends": "../../tsconfig.json",
  "compilerOptions": {
    "rootDir": "./src",
    "outDir": "./dist",
    "declarationDir": "./dist"
  },
  "include": ["src/**/*"],
  "exclude": ["src/**/*.test.ts"]
}

import { describe, expect, it } from "vitest";
import { add } from "./math";

describe("add", () => {
	it("returns the sum of two numbers", () => {
		expect(add(2, 3)).toBe(5);
		expect(add(0, 0)).toBe(0);
		expect(add(-1, 1)).toBe(0);
	});
});

import { defineConfig } from "vitest/config";

export default defineConfig({
	root: __dirname,
	test: {
		globals: true,
	},
});

export function add(a: number, b: number): number {
	return a + b;
}

