  "compilerOptions": {
    "target": "ES2017",
    "module": "ESNext",
    "moduleResolution": "bundler",
    "jsx": "preserve",
    "allowJs": true,
    "noEmit": true,
    "incremental": true,
    "resolveJsonModule": true,
    "isolatedModules": true,
    "plugins": [
      {
        "name": "next"
      }
    ],
    "paths": {
      "@/*": ["./src/*"]
    }
  },
  "include": [
    "next-env.d.ts",
    "**/*.ts",
    "**/*.tsx",
    ".next/types/**/*.ts"
  ],
  "exclude": [
    "node_modules",
    "**/*.test.ts",
    "**/*.test.tsx",
    "e2e"
  ]
}

import type { NextConfig } from "next";

const nextConfig: NextConfig = {
  output: "standalone",
};

export default nextConfig;

import type { PlaywrightTestConfig } from "@playwright/test";

const config: PlaywrightTestConfig = {
  testDir: "./e2e",
  fullyParallel: true,
  forbidOnly: !!process.env.CI,
  retries: process.env.CI ? 2 : 0,
  workers: process.env.CI ? 1 : undefined,
  reporter: "list",
  use: {
    baseURL: "http://localhost:3000",
    trace: "on-first-retry",
  },
  webServer: {
    command: "pnpm dev",
    url: "http://localhost:3000",
    reuseExistingServer: !process.env.CI,
    timeout: 120000,
  },
};

export default config;

/// <reference types="vitest/config" />
import { defineConfig } from "vitest/config";

export default defineConfig({
  root: __dirname,
  test: {
    globals: true,
    browser: {
      provider: "playwright",
      enabled: true,
      name: "chromium",
    },
  },
});

import type { Metadata } from "next";

export const metadata: Metadata = {
	title: "Addition Visualizer",
};

export default function RootLayout({
	children,
}: Readonly<{
	children: React.ReactNode;
}>) {
	return (
		<html lang="en">
			<body>{children}</body>
		</html>
	);
}

"use client";

import { AdditionVisualizer } from "@/components/AdditionVisualizer";

export default function Home() {
	return (
		<main>
			<h1>Add Two Numbers</h1>
			<AdditionVisualizer />
		</main>
	);
}

"use client";

import { add } from "myapp-lib";
import { useState } from "react";

export function AdditionVisualizer() {
	const [a, setA] = useState(0);
	const [b, setB] = useState(0);

	const result = add(a, b);

	return (
		<div>
			<label>
				Operand A:
				<input
					type="number"
					value={a}
					onChange={(e) => setA(Number(e.target.value))}
					data-testid="operand-a"
				/>
			</label>
			<label>
				Operand B:
				<input
					type="number"
					value={b}
					onChange={(e) => setB(Number(e.target.value))}
					data-testid="operand-b"
				/>
			</label>
			<div data-testid="result">Result: {result}</div>
		</div>
	);
}

body {
	font-family: system-ui, sans-serif;
	padding: 1rem;
}

import { render, screen } from "@testing-library/react";
import { describe, expect, it } from "vitest";
import { AdditionVisualizer } from "./AdditionVisualizer";

describe("AdditionVisualizer", () => {
	it("renders with default values", () => {
		render(<AdditionVisualizer />);
		expect(screen.getByTestId("operand-a")).toHaveValue(0);
		expect(screen.getByTestId("operand-b")).toHaveValue(0);
		expect(screen.getByTestId("result")).toHaveTextContent("Result: 0");
	});

	it("updates result when operands change", async () => {
		render(<AdditionVisualizer />);
		const inputA = screen.getByTestId("operand-a");
		const inputB = screen.getByTestId("operand-b");

		// Type a new value in each input
		inputA.setAttribute("value", "5");
		inputA.dispatchEvent(new Event("change", { bubbles: true }));

		inputB.setAttribute("value", "3");
		inputB.dispatchEvent(new Event("change", { bubbles: true }));

		// Wait for React state update
		await new Promise((resolve) => setTimeout(resolve, 0));

		expect(screen.getByTestId("result")).toHaveTextContent("Result: 8");
	});
});

import { render, screen } from "@testing-library/react";
import { describe, expect, it } from "vitest";
import { AdditionVisualizer } from "./AdditionVisualizer";

describe("AdditionVisualizer", () => {
	it("renders with default values", () => {
		render(<AdditionVisualizer />);
		expect(screen.getByTestId("operand-a")).toHaveValue(0);
		expect(screen.getByTestId("operand-b")).toHaveValue(0);
		expect(screen.getByTestId("result")).toHaveTextContent("Result: 0");
	});

	it("updates result when operands change", async () => {
		render(<AdditionVisualizer />);
		const inputA = screen.getByTestId("operand-a");
		const inputB = screen.getByTestId("operand-b");

		// Type a new value in each input
		inputA.setAttribute("value", "5");
		inputA.dispatchEvent(new Event("change", { bubbles: true }));

		inputB.setAttribute("value", "3");
		inputB.dispatchEvent(new Event("change", { bubbles: true }));

		// Wait for React state update
		await new Promise((resolve) => setTimeout(resolve, 0));

		expect(screen.getByTestId("result")).toHaveTextContent("Result: 8");
	});
});

import { describe, expect, it } from "vitest";
import { render, screen } from "vitest-browser-react";
import { AdditionVisualizer } from "./AdditionVisualizer";

describe("AdditionVisualizer", () => {
	it("renders with default values", () => {
		render(<AdditionVisualizer />);
		const inputA = screen.getByTestId("operand-a");
		const inputB = screen.getByTestId("operand-b");
		const result = screen.getByTestId("result");

		expect((inputA as HTMLInputElement).value).toBe("0");
		expect((inputB as HTMLInputElement).value).toBe("0");
		expect(result.textContent).toBe("Result: 0");
	});

	it("updates result when operands change", async () => {
		render(<AdditionVisualizer />);
		const inputA = screen.getByTestId("operand-a");
		const inputB = screen.getByTestId("operand-b");

		(inputA as HTMLInputElement).value = "5";
		inputA.dispatchEvent(new Event("change", { bubbles: true }));

		(inputB as HTMLInputElement).value = "3";
		inputB.dispatchEvent(new Event("change", { bubbles: true }));

		// Wait for React state update
		await new Promise((resolve) => setTimeout(resolve, 0));

		const result = screen.getByTestId("result");
		expect(result.textContent).toBe("Result: 8");
	});
});

import { test, expect } from "@playwright/test";

test.describe("Addition Visualizer", () => {
	test.beforeEach(async ({ page }) => {
		await page.goto("http://localhost:3000");
	});

	test("shows heading and visualizer", async ({ page }) => {
		await expect(
			page.getByRole("heading", { name: "Add Two Numbers" }),
		).toBeVisible();
		await expect(page.getByTestId("operand-a")).toBeVisible();
		await expect(page.getByTestId("operand-b")).toBeVisible();
		await expect(page.getByTestId("result")).toHaveText("Result: 0");
	});

	test("updates result when typing operands", async ({ page }) => {
		const inputA = page.getByTestId("operand-a");
		const inputB = page.getByTestId("operand-b");
		const result = page.getByTestId("result");

		await inputA.fill("7");
		await expect(result).toHaveText("Result: 7");

		await inputB.fill("5");
		await expect(result).toHaveText("Result: 12");
	});
});

